package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonSyntaxException;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class GsonFromJsonStringTypeTokenTest {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void fromJson_nullJson_returnsNull() {
    TypeToken<String> typeToken = TypeToken.get(String.class);
    String result = gson.fromJson((String) null, typeToken);
    assertNull(result);
  }

  @Test
  public void fromJson_validJsonString_returnsObject() {
    String json = "\"test string\"";
    TypeToken<String> typeToken = TypeToken.get(String.class);
    String result = gson.fromJson(json, typeToken);
    assertEquals("test string", result);
  }

  @Test
  public void fromJson_invalidJson_throwsJsonSyntaxException() {
    String invalidJson = "{unclosed json}";
    TypeToken<Object> typeToken = TypeToken.get(Object.class);
    assertThrows(JsonSyntaxException.class, () -> gson.fromJson(invalidJson, typeToken));
  }

  @Test
  public void fromJson_emptyJsonString_returnsNullOrThrows() {
    TypeToken<String> typeToken = TypeToken.get(String.class);
    // Empty string is invalid JSON, expect JsonSyntaxException
    assertThrows(JsonSyntaxException.class, () -> gson.fromJson("", typeToken));
  }

  @Test
  public void fromJson_invokesPrivateFromJsonReaderMethod() throws Exception {
    String json = "\"reflection test\"";
    TypeToken<String> typeToken = TypeToken.get(String.class);

    Method fromJsonReaderMethod = Gson.class.getDeclaredMethod("fromJson", java.io.Reader.class, TypeToken.class);
    fromJsonReaderMethod.setAccessible(true);

    java.io.Reader reader = new java.io.StringReader(json);
    @SuppressWarnings("unchecked")
    String result = (String) fromJsonReaderMethod.invoke(gson, reader, typeToken);

    assertEquals("reflection test", result);
  }
}
